
-- LONDON UNDERGROUND: 
-- Database Creation

-- Source: Transport for London Open Data
-- Coverage: 2010-2026 journey data, 2019/2023/2024 station data,
--           2004-2017 line performance data


CREATE DATABASE london_underground;
USE london_underground;


-- TABLE 1: JOURNEYS BY MODE
-- 205 TfL reporting periods (4-weekly), Apr 2010 to Jan 2026


CREATE TABLE journeys_by_mode (
    fin_year            VARCHAR(10),
    period_num          INT,
    period_start        DATE,
    period_end          DATE,
    days                INT,
    bus_m               DECIMAL(10,3) COMMENT 'Bus journeys in millions',
    underground_m       DECIMAL(10,3) COMMENT 'Underground journeys in millions',
    dlr_m               DECIMAL(10,3),
    tram_m              DECIMAL(10,3),
    overground_m        DECIMAL(10,3),
    cable_car_m         DECIMAL(10,3),
    tfl_rail_m          DECIMAL(10,3),
    total_m             DECIMAL(10,3),
    underground_daily_m DECIMAL(10,3),
    bus_daily_m         DECIMAL(10,3),
    PRIMARY KEY (fin_year, period_num)
);




-- TABLE 2: STATION RECOVERY (2019 vs 2023 vs 2024)
-- 419 stations matched across all 3 years


CREATE TABLE station_recovery (
    Station                 VARCHAR(100),
    Mode                    VARCHAR(10),
    annual_2019             DECIMAL(15,2),
    weekday_entry_2019      DECIMAL(10,2),
    sat_entry_2019          DECIMAL(10,2),
    sun_entry_2019          DECIMAL(10,2),
    annual_2023             DECIMAL(15,2),
    midweek_entry_2023      DECIMAL(10,2),
    monday_entry_2023       DECIMAL(10,2),
    sat_entry_2023          DECIMAL(10,2),
    annual_2024             DECIMAL(15,2),
    midweek_entry_2024      DECIMAL(10,2),
    monday_entry_2024       DECIMAL(10,2),
    sat_entry_2024          DECIMAL(10,2),
    recovery_pct_2023       DECIMAL(5,1),
    recovery_pct_2024       DECIMAL(5,1),
    change_2023_to_2024     DECIMAL(5,1),
    monday_vs_midweek_2024  DECIMAL(5,1) COMMENT 'Monday entries vs Tue-Thu, negative = Monday weakness',
    sat_recovery_pct        DECIMAL(5,1),
    recovery_category       VARCHAR(50),
    PRIMARY KEY (Station, Mode)
);




-- TABLE 3: LINE PERFORMANCE (2004-2017)
-- 5 metrics × 11 lines × 13 years


CREATE TABLE line_performance (
    line            VARCHAR(30),
    metric          VARCHAR(50),
    financial_year  VARCHAR(10),
    value           DECIMAL(15,4),
    INDEX idx_line (line),
    INDEX idx_metric (metric)
);




-- TABLE 4: ANNUAL MODE SUMMARY
-- Financial year totals for each transport mode


CREATE TABLE annual_mode_summary (
    fin_year            VARCHAR(10) PRIMARY KEY,
    underground_total   DECIMAL(10,3),
    bus_total           DECIMAL(10,3),
    dlr_total           DECIMAL(10,3),
    tram_total          DECIMAL(10,3),
    overground_total    DECIMAL(10,3),
    total_all           DECIMAL(10,3),
    periods             INT,
    tube_share_pct      DECIMAL(5,1),
    bus_share_pct       DECIMAL(5,1)
);





